import{c as a,Q as t,j as i,m as e}from"./chunks/framework.Bhbi9jCp.js";const c=JSON.parse('{"title":"GOP、I/P/B 帧、关键帧","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/06-GOP-IPB帧-关键帧.md","filePath":"mediaTechLearning/06-GOP-IPB帧-关键帧.md","lastUpdated":1780887690000}'),n={name:"mediaTechLearning/06-GOP-IPB帧-关键帧.md"};function p(h,s,l,d,r,o){return t(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="gop、i-p-b-帧、关键帧" tabindex="-1">GOP、I/P/B 帧、关键帧 <a class="header-anchor" href="#gop、i-p-b-帧、关键帧" aria-label="Permalink to &quot;GOP、I/P/B 帧、关键帧&quot;">​</a></h1><p>视频压缩能省那么多,核心原因是:<strong>不是每一帧都完整存</strong>。</p><blockquote><p>一句话先记住:<strong>I 帧是完整图,P/B 帧是参考别的帧算出来的差异,GOP 是从一个关键帧到下一个关键帧之间的一组帧</strong>。拖动、首帧、HLS 切片、直播延迟都绕不开 GOP。</p></blockquote><hr><h2 id="一、三类帧" tabindex="-1">一、三类帧 <a class="header-anchor" href="#一、三类帧" aria-label="Permalink to &quot;一、三类帧&quot;">​</a></h2><table tabindex="0"><thead><tr><th>帧</th><th>依赖</th><th>特点</th></tr></thead><tbody><tr><td>I 帧</td><td>不依赖其他帧</td><td>大,可独立解码</td></tr><tr><td>P 帧</td><td>参考过去帧</td><td>较小</td></tr><tr><td>B 帧</td><td>参考过去和未来帧</td><td>更小,但增加重排序</td></tr></tbody></table><p>简化结构:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I B B P B B P B B I</span></span></code></pre></div><p>播放器想从中间开始播,通常要等到最近的 I 帧。因为 P/B 帧单独拿出来解不出完整画面。</p><hr><h2 id="二、gop-是什么" tabindex="-1">二、GOP 是什么 <a class="header-anchor" href="#二、gop-是什么" aria-label="Permalink to &quot;二、GOP 是什么&quot;">​</a></h2><p>GOP(Group of Pictures):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I ... P/B ... P/B | I ... P/B ... P/B</span></span>
<span class="line"><span>^                 ^</span></span>
<span class="line"><span>一个 GOP           下一个 GOP</span></span></code></pre></div><p>GOP 长度常用&quot;多少帧&quot;或&quot;多少秒&quot;描述:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>30fps 下 GOP=60 -&gt; 2 秒一个关键帧</span></span></code></pre></div><hr><h2 id="三、gop-长短的取舍" tabindex="-1">三、GOP 长短的取舍 <a class="header-anchor" href="#三、gop-长短的取舍" aria-label="Permalink to &quot;三、GOP 长短的取舍&quot;">​</a></h2><table tabindex="0"><thead><tr><th>GOP</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>短</td><td>拖动快,首帧快,切片方便</td><td>码率更高</td></tr><tr><td>长</td><td>压缩效率好</td><td>拖动慢,恢复慢,延迟可能高</td></tr></tbody></table><p>直播常见 2 秒 GOP,因为 HLS 分片和关键帧要对齐。会议低延迟场景会更关注关键帧请求和丢包恢复。</p><hr><h2 id="四、b-帧为什么影响延迟" tabindex="-1">四、B 帧为什么影响延迟 <a class="header-anchor" href="#四、b-帧为什么影响延迟" aria-label="Permalink to &quot;四、B 帧为什么影响延迟&quot;">​</a></h2><p>B 帧可能参考未来帧:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>显示顺序: I B B P</span></span>
<span class="line"><span>解码顺序: I P B B</span></span></code></pre></div><p>这就引入重排序缓存。离线点播没问题,低延迟直播和 WebRTC 要谨慎。很多实时编码会减少甚至不用 B 帧。</p><hr><h2 id="五、强制关键帧" tabindex="-1">五、强制关键帧 <a class="header-anchor" href="#五、强制关键帧" aria-label="Permalink to &quot;五、强制关键帧&quot;">​</a></h2><p>转 HLS 时常需要固定关键帧间隔:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -keyint_min</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sc_threshold</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>含义:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-g 60              最大 GOP 60 帧</span></span>
<span class="line"><span>-keyint_min 60     最小 GOP 60 帧</span></span>
<span class="line"><span>-sc_threshold 0    禁用场景切换自动插关键帧</span></span></code></pre></div><p>这是为了让切片边界更可控。</p><hr><h2 id="六、排查关键帧" tabindex="-1">六、排查关键帧 <a class="header-anchor" href="#六、排查关键帧" aria-label="Permalink to &quot;六、排查关键帧&quot;">​</a></h2><p>看帧类型:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -select_streams</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -show_frames</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -show_entries</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> frame=pict_type,key_frame,pts_time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -of</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> csv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span></span></code></pre></div><p>看关键帧间隔是否稳定。HLS 卡顿、拖动慢、首帧慢时,先查 GOP。</p><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>GOP 太长</strong>——拖动和首帧变慢。</li><li><strong>切片不对齐关键帧</strong>——播放器容易卡或花屏。</li><li><strong>低延迟场景乱用 B 帧</strong>——重排序增加延迟。</li><li><strong>只调码率不调 GOP</strong>——画质和延迟都可能不稳定。</li><li><strong>不了解 IDR</strong>——不是所有 I 帧都一定能安全刷新解码状态。</li></ol><p>下一篇:<code>07-FFmpeg 心智模型.md</code>。</p>`,40)])])}const g=a(n,[["render",p]]);export{c as __pageData,g as default};
